import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { API_ENDPOINTS, getApiUrl, API_BASE_URL } from '../config/api';
import { useAuth } from '../context/AuthContext';
import api from '../services/api';
import toast from 'react-hot-toast';

// Types (simplified for brevity)
interface ServiceType {
  id: number;
  service_type: string;
  pricing: PricingField[];
}
interface PricingField {
  id: number;
  room_size: string;
  price: number;
}
interface CartItem {
  serviceTypeId: number;
  serviceType: string;
  room_size: string;
  price: number;
  quantity: number;
}

const ServiceDetails: React.FC = () => {
  const { serviceName } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();

  const [serviceInfo, setServiceInfo] = useState<any>(null);
  const [serviceTypes, setServiceTypes] = useState<ServiceType[]>([]);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [currentStep, setCurrentStep] = useState<'types' | 'details' | 'confirmation'>('types');
  const [selectedDate, setSelectedDate] = useState('');
  const [selectedTime, setSelectedTime] = useState('');
  const [address, setAddress] = useState('');
  const [notes, setNotes] = useState('');
  const [couponCode, setCouponCode] = useState('');
  const [isCouponApplied, setIsCouponApplied] = useState(false);
  const [couponDiscount, setCouponDiscount] = useState(0);
  const [appliedCouponCode, setAppliedCouponCode] = useState('');
  const [selectedPaymentMethod, setSelectedPaymentMethod] = useState('cash');
  const [agreedToTerms, setAgreedToTerms] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    fetchServiceDetails();
    // eslint-disable-next-line
  }, [serviceName]);

  const fetchServiceDetails = async () => {
    try {
      const response = await api.get(getApiUrl(API_ENDPOINTS.GET_USER_SERVICE_DETAILS) + `?service_name=${encodeURIComponent(serviceName || '')}`);
      if (response.status === 'success') {
        setServiceInfo(response.service_info);
        setServiceTypes(response.data);
      } else {
        toast.error(response.message || 'Service not found');
      }
    } catch (error) {
      toast.error('Failed to fetch service details');
    }
  };

  const addToCart = (serviceType: ServiceType, pricingField: PricingField) => {
    setCart((prev) => {
      const idx = prev.findIndex(
        (item) => item.serviceTypeId === serviceType.id && item.room_size === pricingField.room_size
      );
      if (idx !== -1) {
        const updated = [...prev];
        updated[idx].quantity += 1;
        return updated;
      }
      return [
        ...prev,
        {
          serviceTypeId: serviceType.id,
          serviceType: serviceType.service_type,
          room_size: pricingField.room_size,
          price: pricingField.price,
          quantity: 1,
        },
      ];
    });
  };

  const removeFromCart = (serviceTypeId: number, room_size: string) => {
    setCart((prev) => {
      const idx = prev.findIndex(
        (item) => item.serviceTypeId === serviceTypeId && item.room_size === room_size
      );
      if (idx !== -1) {
        const updated = [...prev];
        if (updated[idx].quantity > 1) {
          updated[idx].quantity -= 1;
        } else {
          updated.splice(idx, 1);
        }
        return updated;
      }
      return prev;
    });
  };

  const getCartItemQuantity = (serviceTypeId: number, room_size: string) => {
    const item = cart.find(
      (item) => item.serviceTypeId === serviceTypeId && item.room_size === room_size
    );
    return item ? item.quantity : 0;
  };

  const calculateSubtotal = () => {
    return cart.reduce((sum, item) => sum + item.price * item.quantity, 0);
  };
  const calculateDiscount = () => {
    return calculateSubtotal() * 0.15;
  };
  const calculateTotal = () => {
    return calculateSubtotal() - calculateDiscount() - couponDiscount;
  };

  const applyCoupon = async () => {
    if (!couponCode.trim()) {
      toast.error('Please enter a coupon code');
      return;
    }
    try {
      const orderAmount = calculateSubtotal();
      const response = await api.get(
        getApiUrl(API_ENDPOINTS.BOOK_SERVICE) +
          `?action=validate_coupon&coupon_code=${encodeURIComponent(couponCode.trim())}&order_amount=${orderAmount}`
      );
      if (response?.status === 'success') {
        setCouponDiscount(response.discount_amount);
        setAppliedCouponCode(couponCode.trim());
        setIsCouponApplied(true);
        toast.success(response.message || 'Coupon applied successfully!');
      } else {
        toast.error(response?.message || 'Invalid coupon code');
      }
    } catch (error) {
      toast.error('Failed to validate coupon');
    }
  };
  const removeCoupon = () => {
    setIsCouponApplied(false);
    setCouponDiscount(0);
    setAppliedCouponCode('');
    setCouponCode('');
  };

  const handleRazorpayPayment = () => {
    const options = {
      key: 'rzp_test_TGcPYUXCQVm6fX',
      amount: Math.round(calculateTotal() * 100),
      currency: 'INR',
      name: 'NPC Services',
      description: serviceInfo?.service_name || 'Service Booking',
      handler: function (response: any) {
        handleBooking({
          razorpay_payment_id: response.razorpay_payment_id,
          razorpay_order_id: response.razorpay_order_id,
          razorpay_signature: response.razorpay_signature,
        });
      },
      prefill: {
        email: user?.email || '',
        contact: user?.mobile || '',
      },
      theme: {
        color: '#0F766E',
      },
    };
    // @ts-ignore
    const rzp = new window.Razorpay(options);
    rzp.open();
    rzp.on('payment.failed', function (response: any) {
      toast.error('Payment failed: ' + response.error.description);
    });
  };

  const handleBooking = async (razorpayDetails?: any) => {
    if (!selectedDate || !selectedTime || !address || !agreedToTerms) {
      toast.error('Please fill all details and agree to terms');
      return;
    }
    if (cart.length === 0) {
      toast.error('Please add at least one service');
      return;
    }
    setIsLoading(true);
    try {
      const bookingData = {
        action: 'create_booking',
        service_name: serviceInfo?.service_name,
        service_date: selectedDate,
        time_slot: selectedTime,
        service_address: address,
        special_notes: notes,
        subtotal: calculateSubtotal(),
        discount_amount: calculateDiscount(),
        coupon_code: isCouponApplied ? appliedCouponCode : undefined,
        coupon_discount: couponDiscount,
        total_amount: calculateTotal(),
        payment_method: selectedPaymentMethod,
        cart_items: cart,
        ...razorpayDetails,
      };
      const response = await api.post(getApiUrl(API_ENDPOINTS.BOOK_SERVICE), bookingData);
      if (response.status === 'success') {
        toast.success('Booking successful!');
        navigate('/user-dashboard');
      } else {
        toast.error(response.message || 'Booking failed');
      }
    } catch (error) {
      toast.error('Booking failed');
    } finally {
      setIsLoading(false);
    }
  };

  // UI rendering (simplified for brevity)
  return (
    <div className="max-w-3xl mx-auto p-4">
      <h2 className="text-2xl font-bold mb-4">{serviceInfo?.service_name || 'Service Details'}</h2>
      {currentStep === 'types' && (
        <div>
          <h3 className="text-lg font-semibold mb-2">Choose Service Types</h3>
          {serviceTypes.map((type) => (
            <div key={type.id} className="mb-4">
              <div className="font-medium mb-1">{type.service_type}</div>
              {type.pricing.map((pricing) => (
                <div key={pricing.id} className="flex items-center mb-1">
                  <span className="w-32">{pricing.room_size}</span>
                  <span className="w-20">₹{pricing.price}</span>
                  <button
                    className="px-2 py-1 bg-green-600 text-white rounded ml-2"
                    onClick={() => addToCart(type, pricing)}
                  >
                    +
                  </button>
                  <span className="mx-2">{getCartItemQuantity(type.id, pricing.room_size)}</span>
                  <button
                    className="px-2 py-1 bg-red-600 text-white rounded"
                    onClick={() => removeFromCart(type.id, pricing.room_size)}
                    disabled={getCartItemQuantity(type.id, pricing.room_size) === 0}
                  >
                    -
                  </button>
                </div>
              ))}
            </div>
          ))}
          <button
            className="mt-4 px-4 py-2 bg-blue-600 text-white rounded"
            onClick={() => setCurrentStep('details')}
            disabled={cart.length === 0}
          >
            Next
          </button>
        </div>
      )}
      {currentStep === 'details' && (
        <div>
          <h3 className="text-lg font-semibold mb-2">Booking Details</h3>
          <input
            type="date"
            className="border p-2 mb-2 w-full"
            value={selectedDate}
            onChange={(e) => setSelectedDate(e.target.value)}
          />
          <select
            className="border p-2 mb-2 w-full"
            value={selectedTime}
            onChange={(e) => setSelectedTime(e.target.value)}
          >
            <option value="">Select Time Slot</option>
            <option value="9:00 AM - 11:00 AM">9:00 AM - 11:00 AM</option>
            <option value="11:00 AM - 1:00 PM">11:00 AM - 1:00 PM</option>
            <option value="2:00 PM - 4:00 PM">2:00 PM - 4:00 PM</option>
            <option value="4:00 PM - 6:00 PM">4:00 PM - 6:00 PM</option>
            <option value="6:00 PM - 8:00 PM">6:00 PM - 8:00 PM</option>
          </select>
          <input
            type="text"
            className="border p-2 mb-2 w-full"
            placeholder="Address"
            value={address}
            onChange={(e) => setAddress(e.target.value)}
          />
          <textarea
            className="border p-2 mb-2 w-full"
            placeholder="Special Notes"
            value={notes}
            onChange={(e) => setNotes(e.target.value)}
          />
          <div className="flex items-center mb-2">
            <input
              type="checkbox"
              checked={agreedToTerms}
              onChange={(e) => setAgreedToTerms(e.target.checked)}
              className="mr-2"
            />
            <span>I agree to the terms and conditions</span>
          </div>
          <button
            className="mt-2 px-4 py-2 bg-blue-600 text-white rounded"
            onClick={() => setCurrentStep('confirmation')}
            disabled={!selectedDate || !selectedTime || !address || !agreedToTerms}
          >
            Next
          </button>
        </div>
      )}
      {currentStep === 'confirmation' && (
        <div>
          <h3 className="text-lg font-semibold mb-2">Confirm Booking</h3>
          <div className="mb-2">Subtotal: ₹{calculateSubtotal()}</div>
          <div className="mb-2">Discount: ₹{calculateDiscount()}</div>
          {isCouponApplied && (
            <div className="mb-2">Coupon ({appliedCouponCode}): -₹{couponDiscount}</div>
          )}
          <div className="mb-2 font-bold">Total: ₹{calculateTotal()}</div>
          <div className="mb-2">
            <input
              type="text"
              className="border p-2 mr-2"
              placeholder="Coupon Code"
              value={couponCode}
              onChange={(e) => setCouponCode(e.target.value)}
              disabled={isCouponApplied}
            />
            {!isCouponApplied ? (
              <button className="px-3 py-2 bg-green-600 text-white rounded" onClick={applyCoupon}>Apply</button>
            ) : (
              <button className="px-3 py-2 bg-gray-400 text-white rounded" onClick={removeCoupon}>Remove</button>
            )}
          </div>
          <div className="mb-2">
            <label className="mr-4">
              <input
                type="radio"
                name="payment"
                value="cash"
                checked={selectedPaymentMethod === 'cash'}
                onChange={() => setSelectedPaymentMethod('cash')}
              />
              Cash on Delivery
            </label>
            <label>
              <input
                type="radio"
                name="payment"
                value="razorpay"
                checked={selectedPaymentMethod === 'razorpay'}
                onChange={() => setSelectedPaymentMethod('razorpay')}
              />
              Pay Online (Razorpay)
            </label>
          </div>
          <button
            className="mt-4 px-4 py-2 bg-blue-600 text-white rounded"
            onClick={() => {
              if (selectedPaymentMethod === 'razorpay') {
                handleRazorpayPayment();
              } else {
                handleBooking();
              }
            }}
            disabled={isLoading}
          >
            {isLoading ? 'Processing...' : 'Book Now'}
          </button>
        </div>
      )}
    </div>
  );
};

export default ServiceDetails;
